import React, { useEffect, useState } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import api from '../api';

const ProductDetails = () => {
  const { id } = useParams();
  const [product, setProduct] = useState(null);
  const [error, setError] = useState('');
  const userId = Number(localStorage.getItem('userId'));
  const navigate = useNavigate();

  useEffect(() => {
    const fetchProduct = async () => {
      try {
        const res = await api.get(`products/${id}`);
        setProduct(res.data);
      } catch (err) {
        setError('Product not found');
      }
    };
    fetchProduct();
  }, [id]);

  const handleDelete = async () => {
    try {
      await api.delete(`products/${id}`);
      navigate('/');
    } catch (err) {
      setError('Could not delete product');
    }
  };

  const addToWishlist = async () => {
    try {
      await api.post(`wishlist/${id}`);
      alert('Added to wishlist');
    } catch (err) {
      alert('Failed to add to wishlist');
    }
  };

  if (error) return <p>{error}</p>;
  if (!product) return <p>Loading...</p>;

  const isOwner = userId === product.sellerId;

  const handleBuy = async () => {
    try {
      await api.post(`products/${id}/buy`);
      setProduct({ ...product, sold: true });
      alert('Product successfully bought. It is now marked as sold.');
    } catch (err) {
      alert(err.response?.data?.message || 'Could not complete purchase');
    }
  };

  const contactSeller = () => {
    navigate(`/chat?user=${product.sellerId}`);
  };

  return (
    <div>
      <h2>{product.title}</h2>
      {product.imagePath && <img src={`http://localhost:8080${product.imagePath}`} alt={product.title} style={{ maxWidth: 400 }} />}
      <p>{product.description}</p>
      <p>Price: ₹{product.price}</p>
      <p>Category: {product.category}</p>
      <p>Seller: {product.sellerName}</p>
      <p>Status: {product.sold ? 'Sold' : 'Available'}</p>
      <button onClick={addToWishlist}>Add to wishlist</button>

      {isOwner && (
        <>
          <Link to={`/edit/${id}`}><button>Edit</button></Link>
          <button onClick={handleDelete}>Delete</button>
        </>
      )}

      {!isOwner && !product.sold && (
        <>
          <button onClick={handleBuy}>Buy</button>
          <button onClick={contactSeller}>Contact Seller</button>
        </>
      )}

      {!isOwner && product.sold && <p>This product has already been sold.</p>}
    </div>
  );
};

export default ProductDetails;
